// initTokamakAllocType initializes the configuration for a specific AllocType
// using Tokamak's deployment approach
func initTokamakAllocType(root string, allocType AllocType) error {
	log.Info("Initializing Tokamak alloc type", "allocType", allocType)

	// 1. Load state-dump files (generated by Python script)
	statePath := getStatePathForAllocType(root, allocType)

	// Check if state-dump file exists
	if _, err := os.Stat(statePath); err == nil {
		// Load L1 allocs from state-dump
		l1Allocs, err := foundry.LoadForgeAllocs(statePath)
		if err != nil {
			return fmt.Errorf("failed to load L1 allocs from %s: %w", statePath, err)
		}

		mtx.Lock()
		l1AllocsByType[allocType] = l1Allocs
		mtx.Unlock()

		log.Info("Loaded L1 allocs from state-dump", "path", statePath)
	} else {
		log.Warn("State-dump file not found, will use deployment addresses only", "path", statePath)
	}

	// 2. Load deployment addresses from .deploy file
	l1Deployments, err := LoadTokamakDeployment(root)
	if err != nil {
		// If .deploy file doesn't exist, create minimal deployments
		log.Warn("Failed to load deployments, using minimal config", "error", err)
		l1Deployments = createMinimalDeployments()
	}

	// 3. Override with Tokamak-specific addresses if needed
	overrideTokamakAddresses(l1Deployments)

	mtx.Lock()
	l1DeploymentsByType[allocType] = l1Deployments
	mtx.Unlock()

	// 4. Load deploy config
	deployConfigPath := path.Join(root, "packages/tokamak/contracts-bedrock/deploy-config/devnetL1.json")
	deployConfig, err := loadDeployConfig(deployConfigPath)
	if err != nil {
		log.Warn("Failed to load deploy config, using defaults", "error", err)
		deployConfig = createDefaultDeployConfig()
	}

	mtx.Lock()
	deployConfigsByType[allocType] = deployConfig
	mtx.Unlock()

	// 5. Handle L2 allocs for different hardforks
	l2AllocsMap := make(genesis.L2AllocsModeMap)

	// For each hardfork, load the corresponding state-dump
	modes := []genesis.L2AllocsMode{
		genesis.L2AllocsDelta,
		genesis.L2AllocsEcotone,
		genesis.L2AllocsFjord,
		genesis.L2AllocsGranite,
		genesis.L2AllocsHolocene,
		genesis.L2AllocsIsthmus,
		genesis.L2AllocsInterop,
	}

	for _, mode := range modes {
		l2StatePath := getL2StatePathForMode(root, allocType, mode)
		if _, err := os.Stat(l2StatePath); err == nil {
			l2Allocs, err := foundry.LoadForgeAllocs(l2StatePath)
			if err != nil {
				log.Warn("Failed to load L2 allocs", "mode", mode, "error", err)
				continue
			}
			l2AllocsMap[mode] = l2Allocs
		}
	}

	// If we don't have specific hardfork allocs, use the base one for all
	if len(l2AllocsMap) == 0 && statePath != "" {
		if baseAllocs, err := foundry.LoadForgeAllocs(statePath); err == nil {
			for _, mode := range modes {
				l2AllocsMap[mode] = baseAllocs
			}
		}
	}

	mtx.Lock()
	l2AllocsByType[allocType] = l2AllocsMap
	mtx.Unlock()

	log.Info("Tokamak alloc type initialized", "allocType", allocType)
	return nil
}

// getStatePathForAllocType returns the path to the state-dump file for a given AllocType
func getStatePathForAllocType(root string, allocType AllocType) string {
	base := path.Join(root, "packages/tokamak/contracts-bedrock")

	switch allocType {
	case AllocTypeMTCannon, AllocTypeMTCannonNext:
		return path.Join(base, "state-dump-901.json")
	case AllocTypeAltDA:
		return path.Join(base, "state-dump-901.json")
	default:
		return path.Join(base, "state-dump-901.json")
	}
}

// getL2StatePathForMode returns the path to the L2 state-dump file for a given mode
func getL2StatePathForMode(root string, allocType AllocType, mode genesis.L2AllocsMode) string {
	base := path.Join(root, "packages/tokamak/contracts-bedrock")

	switch mode {
	case genesis.L2AllocsDelta:
		return path.Join(base, "state-dump-901-delta.json")
	case genesis.L2AllocsEcotone:
		return path.Join(base, "state-dump-901-ecotone.json")
	default:
		return path.Join(base, "state-dump-901.json")
	}
}

