// loadDeployConfig loads the deploy config from a JSON file
func loadDeployConfig(path string) (*genesis.DeployConfig, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("failed to read deploy config: %w", err)
	}

	var config genesis.DeployConfig
	if err := json.Unmarshal(data, &config); err != nil {
		return nil, fmt.Errorf("failed to unmarshal deploy config: %w", err)
	}

	return &config, nil
}

// createDefaultDeployConfig creates a minimal default deploy config
func createDefaultDeployConfig() *genesis.DeployConfig {
	// Create an empty deploy config with nested structs initialized
	config := &genesis.DeployConfig{}
	// The actual fields are in nested structs, not direct fields
	// Most values will be zero/empty which is fine for minimal testing
	return config
}

// createMinimalDeployments creates minimal L1 deployments for testing
func createMinimalDeployments() *genesis.L1Deployments {
	return &genesis.L1Deployments{
		// Set minimal addresses for testing
		// These will be overridden when actual deployment is available
	}
}

// InitTokamakConfig initializes all Tokamak configurations
func InitTokamakConfig(root string) error {
	log.Info("Initializing Tokamak E2E configuration")

	// Initialize all alloc types in parallel
	var wg sync.WaitGroup
	errors := make(chan error, len(allocTypes))

	for _, allocType := range allocTypes {
		wg.Add(1)
		go func(at AllocType) {
			defer wg.Done()
			if err := initTokamakAllocType(root, at); err != nil {
				errors <- fmt.Errorf("failed to init %s: %w", at, err)
			}
		}(allocType)
	}

	wg.Wait()
	close(errors)

	// Check for errors
	for err := range errors {
		if err != nil {
			return err
		}
	}

	log.Info("Tokamak E2E configuration initialized successfully")
	return nil
}